changeSet.sql:
CREATE TABLE "control_plane"."currency_exchange_rate" (
  "id"                  uuid,
  "created_at"          timestamptz     NOT NULL DEFAULT now(),
  "effective_at"        timestamptz     NOT NULL,
  "base_currency_code"  varchar(3)      NOT NULL,
  "quote_currency_code" varchar(3)      NOT NULL,
  "rate"                numeric(18,8)   NOT NULL,
  "source"              text            NOT NULL,
  --
  PRIMARY KEY ("id"),
  FOREIGN KEY ("base_currency_code")  REFERENCES "control_plane"."currency"("code") ON DELETE CASCADE,
  FOREIGN KEY ("quote_currency_code") REFERENCES "control_plane"."currency"("code") ON DELETE CASCADE
);

CREATE INDEX ON "control_plane"."currency_exchange_rate" ("effective_at");
CREATE INDEX ON "control_plane"."currency_exchange_rate" ("base_currency_code");
CREATE INDEX ON "control_plane"."currency_exchange_rate" ("quote_currency_code");

CREATE TABLE "control_plane"."tenant_currency" (
  "id"            uuid,
  "created_at"    timestamptz NOT NULL DEFAULT now(),
  "updated_at"    timestamptz NOT NULL DEFAULT now(),
  "tenant_id"     uuid        NOT NULL,
  "currency_code" varchar(3)  NOT NULL,
  "is_enabled"    boolean     NOT NULL DEFAULT true,
  --
  PRIMARY KEY ("id"),
  FOREIGN KEY ("currency_code") REFERENCES "control_plane"."currency"("code"),
  FOREIGN KEY ("tenant_id")     REFERENCES "control_plane"."tenant"("id")      ON DELETE CASCADE,
  UNIQUE      ("tenant_id", "currency_code")
);

CREATE INDEX ON "control_plane"."tenant_currency" ("tenant_id");
CREATE INDEX ON "control_plane"."tenant_currency" ("currency_code");
CREATE INDEX ON "control_plane"."tenant_currency" ("is_enabled");

CREATE TABLE "control_plane"."billing_plan" (
  "id"             uuid,
  "created_at"     timestamptz NOT NULL DEFAULT now(),
  "code"           text        NOT NULL,
  "name"           text        NOT NULL,
  "period"         text        NOT NULL,
  "is_active_flag" boolean     NOT NULL DEFAULT true,
  --
  PRIMARY KEY ("id"),
  UNIQUE      ("code")
);

CREATE INDEX ON "control_plane"."billing_plan" ("is_active_flag");
CREATE INDEX ON "control_plane"."billing_plan" ("period");

CREATE TABLE "control_plane"."membership" (
  "id"                      uuid,
  "created_at"              timestamptz NOT NULL DEFAULT now(),
  "updated_at"              timestamptz NOT NULL DEFAULT now(),
  "removed_at"              timestamptz     NULL,
  "role"                    text        NOT NULL,
  "status"                  text        NOT NULL,
  "invited_by_membership_id" uuid           NULL,
  "tenant_id"               uuid        NOT NULL,
  "account_id"              uuid        NOT NULL,
  --
  PRIMARY KEY ("id"),
  FOREIGN KEY ("invited_by_membership_id") REFERENCES "control_plane"."membership"("id"),
  FOREIGN KEY ("tenant_id")                REFERENCES "control_plane"."tenant"("id")      ON DELETE SET NULL,
  FOREIGN KEY ("account_id")               REFERENCES "control_plane"."account"("id")     ON DELETE CASCADE
);

CREATE INDEX ON "control_plane"."membership" ("tenant_id");
CREATE INDEX ON "control_plane"."membership" ("account_id");
CREATE INDEX ON "control_plane"."membership" ("invited_by_membership_id");
CREATE INDEX ON "control_plane"."membership" ("status");
CREATE INDEX ON "control_plane"."membership" ("role");

CREATE TABLE "control_plane"."membership_invitation" (
  "id"                    uuid,
  "created_at"            timestamptz NOT NULL DEFAULT now(),
  "expires_at"            timestamptz     NULL,
  "accepted_at"           timestamptz     NULL,
  "revoked_at"            timestamptz     NULL,
  "invited_email_address" text        NOT NULL,
  "role"                  text        NOT NULL,
  "invited_by_membership_id" uuid        NULL,
  "invitation_token_hash" text        NOT NULL,
  "tenant_id"             uuid        NOT NULL,
  --
  PRIMARY KEY ("id"),
  FOREIGN KEY ("invited_by_membership_id") REFERENCES "control_plane"."membership"("id"),
  FOREIGN KEY ("tenant_id")                REFERENCES "control_plane"."tenant"("id")      ON DELETE CASCADE
);

CREATE INDEX ON "control_plane"."membership_invitation" ("tenant_id");
CREATE INDEX ON "control_plane"."membership_invitation" ("invited_by_membership_id");
CREATE INDEX ON "control_plane"."membership_invitation" ("invited_email_address");
CREATE INDEX ON "control_plane"."membership_invitation" ("invitation_token_hash");
